const itemIf = $('If').first().json;
const itemDownload = $('Download file').first();

const asunto = itemIf["ASUNTO CORREO"] || "";
const cuerpoRaw = String(itemIf["NUEVO CORREO"] || "");
const pdf = itemIf["PDF"] || "";

const normalizado = cuerpoRaw
  .replace(/\\n/g, "\n")
  .replace(/\r\n/g, "\n");

const parrafos = normalizado
  .split(/\n\s*\n/)
  .map(p => p.trim())
  .filter(Boolean);

const cuerpoHtml = parrafos
  .map(p => `<p style="margin: 0 0 14px 0;">${p.replace(/\n/g, "<br>")}</p>`)
  .join("");

const html = `
<div style="font-family: Arial, sans-serif; font-size: 14px; line-height: 1.6; text-align: left;">
  ${cuerpoHtml}
  <p style="margin: 18px 0 0 0;"><strong>Adjunto:</strong> ${pdf}</p>
</div>
`;

return [
  {
    json: {
      asunto,
      html,
      pdf
    },
    binary: itemDownload.binary
  }
];

const fijo = $("Code in JavaScript").first();

return $input.all()
  .map(actual => {
    const asunto = (fijo.json.asunto || "").trim();
    let html = fijo.json.html || "";
    const binary = fijo.binary || {};

    const correo = String(actual.json.CORREO || "").trim();
    const nombre = String(actual.json.NOMBRE || "").trim();
    const token = String(actual.json.TOKEN_BAJA || "").trim();

    // Validaciones (NO rompen el flujo)
    if (!correo) {
      console.log(`❌ Correo vacío: ${JSON.stringify(actual.json)}`);
      return null;
    }

    if (!correo.includes("@")) {
      console.log(`❌ Email inválido: ${correo}`);
      return null;
    }

    if (/\s/.test(correo)) {
      console.log(`❌ Múltiples emails o espacios: ${correo}`);
      return null;
    }

    const linkBaja = `https://n8n-n8n.mdvbcf.easypanel.host/webhook/baja-suscripcion?token=${encodeURIComponent(token)}`;

    const htmlFinal = html + `
<hr style="margin-top:20px;">
<p style="font-size:12px; color:#888; text-align:center;">
Si ya no deseas recibir estos correos, puedes darte de baja 
<a href="${linkBaja}" style="color:#888;">aquí</a>.
</p>
`;

    return {
      json: {
        to: correo,
        subject: asunto,
        html: htmlFinal,
        nombre,
        token_baja: token,
      },
      binary,
    };
  })
  .filter(item => item !== null);

